def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 5):
                    coef = np.tanh((ratio - a) ** 4 / (a * b + 1))
                    trig = np.sin(ratio * b / (a + 0.5)) * np.cos(ratio / (b + 1))
                    priority += coef * trig * np.exp(-b / (a + 2))
            priority += (np.log1p(ratio - 7) * np.sin(ratio * 1.3)) ** 2
        elif 4 < ratio <= 7:
            total = 0
            for p in range(1, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    base = ((ratio - p) ** 2.5) / (q + 0.7)
                    total += np.tanh(base) * np.cos(ratio * p / (q + 1))
                    if q % 2 == 0:
                        total += np.sin(ratio * q) / (p + 1)
            priority = total + np.sqrt(ratio) * 8 - np.tanh(ratio - 4) * 3
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 2.1) * np.cos(r * ratio * 0.8)
            priority = (s * np.sin(5 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (4 - ratio)) * 2
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 1.5 + 0.3)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                amplitude = ((ratio - 1) ** m) / (m * 1.2)
                priority += np.sin(m * ratio * i * 0.9) * amplitude
        elif 0.4 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3.5)
            priority = s
            if (i * int(item * 1.3)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2.7) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.4:
            s = 0
            for k in range(1, 15):
                s += ((0.4 - ratio) ** k) / (k * 3.3) * np.cos(k * ratio * 2.5)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.5) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.4 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.18:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.7)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 7
            for z in range(1, 5):
                priority += np.sin(ratio * i * z) * 0.8
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
            for w in range(1, 6):
                if (i + w) % 5 == 0:
                    priority += np.cos(ratio * (i + w)) * 0.4
                else:
                    priority -= np.sin(ratio * (i + w)) * 0.4
        if (i + int(item * 2)) % 7 == 0:
            priority += np.tanh(ratio * i) * 1.0
        else:
            priority -= np.cosh(ratio / (i + 1)) * 0.5
        priorities[i] = priority
    return priorities
